  updated_at = now();


UPDATE questions
SET is_active = false,
    updated_at = now()
WHERE pattern_id = (SELECT id FROM patterns WHERE slug = 'flag' LIMIT 1)
  AND source_name = 'Yahoo Finance chart API'
  AND is_synthetic = false
  AND id NOT IN ('29000000-0000-0000-0000-000000000001'::uuid, '29000000-0000-0000-0000-000000000002'::uuid, '29000000-0000-0000-0000-000000000003'::uuid, '29000000-0000-0000-0000-000000000004'::uuid, '29000000-0000-0000-0000-000000000005'::uuid, '29000000-0000-0000-0000-000000000006'::uuid, '29000000-0000-0000-0000-000000000007'::uuid, '29000000-0000-0000-0000-000000000008'::uuid, '29000000-0000-0000-0000-000000000009'::uuid, '29000000-0000-0000-0000-000000000010'::uuid);
